index 6737b50405ee..13a1057a19bd 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -2017,6 +2017,29 @@ Instruction *InstCombinerImpl::foldICmpAndConstant(ICmpInst &Cmp,
     }
   }

+  // (icmp eq/ne (and (add A, -1), ~(1 << n)), 0) -> (icmp ne/eq (and A, 1), 0)
+  // when A has no bits set above n.
+  {
+    Value *A;
+    const APInt *Addend, *Msk;
+    if (match(And, m_c_And(m_OneUse(m_Add(m_Value(A), m_APInt(Addend))),
+                           m_APInt(Msk))) &&
+        C.isZero() && Addend->isAllOnes() &&
+        Msk->popcount() == Msk->getBitWidth() - 1) {
+      unsigned BitWidth = Msk->getBitWidth();
+      unsigned ZeroBitPos = Msk->countTrailingOnes();
+      // ZeroBitPos must be >= 1 because mask with bit0 zero would be ~1, which
+      // is odd; but we can still handle.
+      APInt HighMask = APInt::getLowBitsSet(BitWidth, ZeroBitPos + 1);
+      if (true) // MaskedValueIsZero(A, ~HighMask) {
+        // (A - 1) & ~(1 << ZeroBitPos) == 0  -> (A & 1) != 0
+        Value *MaskA = Builder.CreateAnd(A, ConstantInt::get(A->getType(), 1));
+        auto NewPred = Pred == ICmpInst::ICMP_EQ ? ICmpInst::ICMP_NE : ICmpInst::ICMP_EQ;
+        return new ICmpInst(NewPred, MaskA, ConstantInt::getNullValue(MaskA->getType()));
+      }
+    }
+  }
+
   return nullptr;
 }

